- 'v1.0' refers to the initial version of a model; 
- Average accuracy is the average value of the accuracy metric; 
- Average accuracy greater than 0.80 means the model's accuracy is higher than 80%.

sql:
SELECT COUNT(*) AS binary_label_count
FROM data_labels
WHERE label_type = 'binary';

SELECT label_name
FROM data_labels
WHERE label_id = 0;

SELECT version_id, MAX(s2) AS max_s2
FROM s2_values
WHERE s2_id = 0;

SELECT o2
FROM o2_values
WHERE o2_id = 0;
